  // ==================== DEPRECATED INPUTS (Backward Compatibility) ====================

  /**
   * @deprecated Use 'notifications' input instead. Will be removed in v2.0.
   * Legacy placement input
   */
  @Input() set placement(value: 'top' | 'bottom' | 'left' | 'right') {
