import {
  Directive,
  Input,
  ElementRef,
  HostListener,
  OnDestroy,
} from '@angular/core';
import { Themeable, ThemeColors } from '@optimistic-tanuki/theme-lib';

@Directive({
  selector: '[otuiTooltip]',
  standalone: true,
})
export class TooltipDirective extends Themeable implements OnDestroy {
  @Input() otuiTooltip = '';
  @Input() tooltipPosition: 'top' | 'bottom' | 'left' | 'right' = 'top';

  private tooltipEl: HTMLElement | null = null;

  constructor(private el: ElementRef) {
    super();
  }

  override applyTheme(colors: ThemeColors): void {
    this.setLocalCSSVariables({
      'tooltip-bg': colors.background,
      'tooltip-color': colors.foreground,
      'tooltip-border': colors.complementary,
    });
  }

  @HostListener('mouseenter')
  onMouseEnter(): void {
    this.showTooltip();
  }

  @HostListener('mouseleave')
  onMouseLeave(): void {
    this.hideTooltip();
  }

  private showTooltip(): void {
    if (this.tooltipEl || !this.otuiTooltip) return;

    this.tooltipEl = document.createElement('div');
    this.tooltipEl.className = 'otui-tooltip';
    this.tooltipEl.textContent = this.otuiTooltip;
    document.body.appendChild(this.tooltipEl);

    this.positionTooltip();
  }

  private positionTooltip(): void {
    if (!this.tooltipEl) return;

    const rect = this.el.nativeElement.getBoundingClientRect();
    const tooltipRect = this.tooltipEl.getBoundingClientRect();

    this.tooltipEl.style.position = 'fixed';
    this.tooltipEl.style.zIndex = '9999';

    switch (this.tooltipPosition) {
      case 'top':
        this.tooltipEl.style.bottom = `${window.innerHeight - rect.top + 8}px`;
        this.tooltipEl.style.left = `${rect.left + rect.width / 2}px`;
        break;
      case 'bottom':
        this.tooltipEl.style.top = `${rect.bottom + 8}px`;
        this.tooltipEl.style.left = `${rect.left + rect.width / 2}px`;
        break;
      case 'left':
        this.tooltipEl.style.top = `${rect.top + rect.height / 2}px`;
        this.tooltipEl.style.right = `${window.innerWidth - rect.left + 8}px`;
        break;
      case 'right':
        this.tooltipEl.style.top = `${rect.top + rect.height / 2}px`;
        this.tooltipEl.style.left = `${rect.right + 8}px`;
        break;
    }

    this.tooltipEl.style.transform = 'translateX(-50%)';
  }

  private hideTooltip(): void {
    if (this.tooltipEl) {
      this.tooltipEl.remove();
      this.tooltipEl = null;
    }
  }

  override ngOnDestroy(): void {
    this.hideTooltip();
  }
}

import {
  Themeable,
  ThemeColors,
  ThemeService,
} from '@optimistic-tanuki/theme-lib';
import { GradientBuilder, GradientType } from '../gradient-builder';
import { Directive, ElementRef, HostBinding, Renderer2 } from '@angular/core';

export function camelToKebab(str: string): string {
  return str.replace(/([a-z0-9])([A-Z])/g, '$1-$2').toLowerCase();
}

export type VariantType =
  | 'default'
  | 'gradient-glow'
  | 'electric-border'
  | 'gradient-glow-card'
  | 'gradient-background'
  | 'custom';

export interface VariantOptions {
  variant?: VariantType;
  backgroundFilter?: string;
  borderColor?: string;
  borderWidth?: string;
  borderRadius?: string;
  borderStyle?: string;
  borderGradient?: string;
  background?: string;
  backgroundGradient?: string;
  svgPattern?: string;
  foreground?: string;
  accent?: string;
  complement?: string;
  glowFilter?: string;
  gradientType?: GradientType;
  gradientStops?: string[];
  gradientColors?: string[];
  transitionDuration?: string;
  animation?: string;
  hoverBoxShadow?: string;
  hoverGradient?: string;
  hoverGlowFilter?: string;
  insetShadow?: string;
  bodyGradient?: string;
  backgroundPattern?: string;
  [key: string]: any;
}

export function variantOptionsToCssVars(
  options: VariantOptions
): Record<string, string> {
  const cssVars: Record<string, string> = {};
  for (const [key, value] of Object.entries(options)) {
    const kebabKey = camelToKebab(key);
    cssVars[`[style.--${kebabKey}]`] = Array.isArray(value)
      ? value.join(', ')
      : String(value) || '';
  }
  return cssVars;
}

@Directive()
export abstract class Variantable extends Themeable {
  variantOptions: VariantOptions = {};

  /**
   * Apply the theme colors and variant options to generate styles.
   */
  abstract applyVariant(colors: ThemeColors, options?: VariantOptions): void;

  applyTheme(colors: ThemeColors): void {
    this.applyVariant(colors);
  }

  /**
   * Utility: Generate gradient CSS string from theme colors and options.
   */
  protected buildGradient(
    colors: string[],
    type: GradientType = 'linear',
    angle = '90deg'
  ): string {
    return new GradientBuilder()
      .setType(type)
      .setOptions({ colors, angle })
      .build();
  }

  /**
   * Utility: Generate SVG pattern string (stub for extension).
   */
  protected buildSVGPattern(type: string, colors: string[]): string {
    // Implement SVG pattern generation logic as needed
    return '';
  }
}

