ul {
  list-style: none;
  padding: 0;
  margin: 0;
  border: var(--local-list-divider, none);
  font-family: var(--font-body, system-ui, sans-serif);
}

.list-item {
  padding: var(--spacing-sm, 8px) var(--spacing-md, 16px);
  cursor: default;
  transition: var(--local-transition-duration, 0.15s) background-color,
    transform;
  border-bottom: var(--local-list-divider, none);
  position: relative;

  &.clickable {
    cursor: pointer;

    &:hover:not(.disabled) {
      background: var(
        --local-list-hover-bg,
        rgba(var(--local-accent-rgb, 177, 186, 236), 0.1)
      );
      transform: translateX(4px);
    }

    &:focus-visible {
      outline: 2px solid var(--local-accent, var(--accent, #3f51b5));
      outline-offset: 2px;
    }
  }

  &.disabled {
    opacity: 0.6;
    cursor: not-allowed;

    &:focus-visible {
      outline: 2px solid var(--local-foreground, var(--foreground, #ffffff));
      outline-offset: 2px;
    }
  }

  &.selected {
    background: var(--local-accent, var(--accent, #3f51b5));
    color: var(--local-foreground, var(--foreground, #ffffff));

    &:focus-visible {
      outline: 2px solid var(--local-foreground, var(--foreground, #ffffff));
      outline-offset: 2px;
    }
  }

  &.has-icon {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm, 8px);
  }

  &.hoverable {
    &:hover:not(.disabled):not(.selected) {
      transform: translateX(2px);
    }
  }
}

.list-icon {
  flex-shrink: 0;
  font-size: var(--font-size-sm, 0.875rem);
  opacity: 0.8;
}

.list-content {
  flex: 1;
  font-family: var(--font-body, system-ui, sans-serif);
}

/* Type variants */
ul.bullet {
  list-style-type: disc;
  padding-left: var(--spacing-lg, 24px);

  .list-item {
    display: list-item;
    list-style-type: disc;
  }
}

ul.numbered {
  list-style-type: decimal;
  padding-left: var(--spacing-lg, 24px);

  .list-item {
    display: list-item;
    list-style-type: decimal;
  }
}

ul.dash {
  list-style-type: square;
  padding-left: var(--spacing-lg, 24px);

  .list-item {
    display: list-item;
    list-style-type: square;
  }
}

ul.none {
  list-style-type: none;
}

/* Layout variants */
ul.horizontal {
  display: flex;
  flex-direction: row;
  gap: var(--spacing-md, 16px);

  .list-item {
    border-bottom: none;
    border-right: var(--local-list-divider, none);
  }
}

/* Size variants */
ul.xs .list-item {
  padding: var(--spacing-xs, 4px) var(--spacing-sm, 8px);
  font-size: var(--font-size-xs, 0.75rem);
}

ul.sm .list-item {
  padding: var(--spacing-xs, 4px) var(--spacing-sm, 8px);
  font-size: var(--font-size-sm, 0.875rem);
}

ul.md .list-item {
  padding: var(--spacing-sm, 8px) var(--spacing-md, 16px);
  font-size: var(--font-size-base, 1rem);
}

ul.lg .list-item {
  padding: var(--spacing-md, 16px) var(--spacing-lg, 24px);
  font-size: var(--font-size-lg, 1.125rem);
}

ul.xl .list-item {
  padding: var(--spacing-lg, 24px) var(--spacing-xl, 32px);
  font-size: var(--font-size-xl, 1.25rem);
}

/* Dividers */
ul.dividers .list-item {
  border-bottom: 1px solid var(--local-border, var(--complement, #c0af4b));

  &:last-child {
    border-bottom: none;
  }
}

/* Variant: glass */
ul.glass {
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: var(--border-radius-md, 8px);

  .list-item {
    &.selected {
      background: rgba(var(--local-accent-rgb, 63, 81, 181), 0.3);
    }

    &.clickable:hover:not(.disabled) {
      background: rgba(var(--local-accent-rgb, 63, 81, 181), 0.15);
    }
  }
}

/* Variant: gradient */
ul.gradient {
  background: linear-gradient(
    135deg,
    var(--local-accent, var(--accent, #3f51b5)) 0%,
    var(--local-complement, var(--complement, #c0af4b)) 100%
  );
  border-radius: var(--border-radius-md, 8px);
  color: var(--local-foreground, var(--foreground, #ffffff));

  .list-item {
    color: var(--local-foreground, var(--foreground, #ffffff));

    &.clickable:hover:not(.disabled) {
      background: rgba(255, 255, 255, 0.2);
    }

    &.selected {
      background: rgba(255, 255, 255, 0.3);
    }

    &:focus-visible {
      outline-color: var(--local-foreground, var(--foreground, #ffffff));
    }
  }

  &.dividers .list-item {
    border-bottom-color: rgba(255, 255, 255, 0.3);
  }
}

/* High contrast mode support */
@media (prefers-contrast: high) {
  .list-item {
    &.selected {
      outline: 2px solid currentColor;
      outline-offset: -2px;
    }

    &:focus-visible {
      outline-width: 3px;
      outline-offset: 2px;
    }
  }
}

/* Reduced motion support */
@media (prefers-reduced-motion: reduce) {
  .list-item {
    transition: none;

    &.clickable:hover:not(.disabled) {
      transform: none;
    }
  }
}

/* Screen reader support - hide icons from screen readers */
.list-icon {
  @media (prefers-contrast: high) {
    opacity: 1;
  }
}

