import {
  Component,
  EventEmitter,
  Input,
  Output,
  ElementRef,
  ViewChild,
  AfterViewInit,
  OnDestroy,
  Renderer2,
  HostListener,
  inject,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { Themeable, ThemeColors } from '@optimistic-tanuki/theme-lib';

/**
 * Modal size options
 */
export type ModalSize = 'sm' | 'md' | 'lg' | 'xl' | 'full';

/**
 * Modal position options
 */
export type ModalPosition =
  | 'center'
  | 'top'
  | 'sidebar-left'
  | 'sidebar-right'
  | 'bottom';

/**
 * Standardized Modal Component
 *
 * Fully accessible modal with focus trap, keyboard navigation, and theme support.
 *
 * @example
 * ```html
 * <otui-modal
 *   [visible]="showModal"
 *   [size]="'lg'"
 *   [position]="'center'"
 *   [closable]="true"
 *   [backdrop]="true"
 *   [ariaLabel]="'User Details'"
 *   (close)="showModal = false"
 * >
 *   <h2 modal-title>User Details</h2>
 *   <p>Modal content here...</p>
 * </otui-modal>
 * ```
 */
@Component({
  selector: 'otui-modal',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './modal.component.html',
  styleUrls: ['./modal.component.scss'],
  host: {
    '[class.theme]': 'theme',
    '[class.variant]': 'variant',
    '[class.size-sm]': 'size === "sm"',
    '[class.size-md]': 'size === "md"',
    '[class.size-lg]': 'size === "lg"',
    '[class.size-xl]': 'size === "xl"',
    '[class.size-full]': 'size === "full"',
    '[class.position-center]': 'position === "center"',
    '[class.position-top]': 'position === "top"',
    '[class.position-sidebar-left]': 'position === "sidebar-left"',
    '[class.position-sidebar-right]': 'position === "sidebar-right"',
    '[class.position-bottom]': 'position === "bottom"',
    '[style.--local-background]': 'background',
    '[style.--local-foreground]': 'foreground',
    '[style.--local-accent]': 'accent',
    '[style.--local-complement]': 'complement',
    '[style.--local-border-color]': 'borderColor',
    '[style.--local-border-gradient]': 'borderGradient',
    '[style.--local-transition-duration]': 'transitionDuration',
  },
})
export class ModalComponent
  extends Themeable
  implements AfterViewInit, OnDestroy
{
  private renderer = inject(Renderer2);

  // ==================== NEW STANDARD INPUTS ====================

  /** Controls modal visibility */
  @Input() visible = false;

  /** Modal heading/title */
  @Input() heading = '';

  /** Modal size */
  @Input() size: ModalSize = 'md';

  /** Modal position */
  @Input() position: ModalPosition = 'center';

  /** Visual variant */
  @Input() variant: 'default' | 'glass' | 'gradient' | 'bordered' = 'default';

  /** Show close button */
  @Input() closable = true;

  /** Show backdrop overlay */
  @Input() backdrop = true;

  /** Close on backdrop click */
  @Input() closeOnBackdrop = true;

  /** Close on Escape key */
  @Input() closeOnEscape = true;

  /** Trap focus within modal */
  @Input() focusTrap = true;

  /** Lock body scroll when modal is open */
  @Input() lockScroll = true;

  /** ARIA label for the dialog */
  @Input() ariaLabel?: string;

  /** ARIA labelledby reference (ID of title element) */
  @Input() ariaLabelledBy?: string;

  /** ARIA describedby reference */
  @Input() ariaDescribedBy?: string;

  /** Custom z-index */
  @Input() zIndex?: number;

  // ==================== OUTPUTS ====================

  /** Emitted when modal is closed */
  @Output() close = new EventEmitter<void>();

  /** Emitted when modal is opened */
  @Output() open = new EventEmitter<void>();

  /** Emitted when backdrop is clicked */
  @Output() backdropClick = new EventEmitter<void>();

  // ==================== DEPRECATED INPUTS (Backward Compatibility) ====================

  /**
   * @deprecated Use 'position' input instead. Will be removed in v2.0.
   */
  @Input() set mode(
    value:
      | 'sidebar'
      | 'sidebar-left'
      | 'trough'
      | 'standard-modal'
      | 'captive-modal'
  ) {
    console.warn(
      `[otui-modal] Warning: "mode" input is deprecated. Use "position" and "size" inputs instead. Will be removed in v2.0.`
    );
    this._legacyMode = value;
    this._convertLegacyMode(value);
  }
  get mode() {
    return this._legacyMode;
  }
  _legacyMode:
    | 'sidebar'
    | 'sidebar-left'
    | 'trough'
    | 'standard-modal'
    | 'captive-modal' = 'standard-modal';

  /**
   * @deprecated Use 'close' output instead. Will be removed in v2.0.
   * This is kept for backward compatibility but will be removed.
   */
  @Output() closeModal = new EventEmitter<void>();

  // ==================== INTERNAL ====================

  @ViewChild('modalDialog', { static: false })
  modalDialog!: ElementRef<HTMLDivElement>;
  @ViewChild('closeButton', { static: false })
  closeButton!: ElementRef<HTMLButtonElement>;

  private focusableElements: HTMLElement[] = [];
  private previouslyFocusedElement: HTMLElement | null = null;
  private bodyScrollLock = false;

  // ==================== LIFECYCLE ====================

  ngAfterViewInit(): void {
    if (this.visible) {
      this.onModalOpen();
    }
  }

  override ngOnDestroy(): void {
    this.unlockBodyScroll();
  }

  // ==================== THEME ====================

  override applyTheme(colors: ThemeColors): void {
    this.background = colors.background;
    this.foreground = colors.foreground;
    this.accent = colors.accent;
    this.complement = colors.complementary;
    this.borderColor = colors.complementary;
    this.borderGradient = colors.complementaryGradients['light'];
    this.transitionDuration = '0.3s';
  }

  // ==================== VISIBILITY HANDLING ====================

  /**
   * Open the modal
   */
  show(): void {
    if (!this.visible) {
      this.visible = true;
      this.open.emit();
      setTimeout(() => this.onModalOpen(), 0);
    }
  }

  /**
   * Close the modal
   */
  hide(): void {
    if (this.visible) {
      this.visible = false;
      this.close.emit();
      this.onModalClose();
    }
  }

  // ==================== EVENT HANDLERS ====================

  @HostListener('document:keydown.escape', ['$event'])
  onEscape(event: Event): void {
    if (this.visible && this.closeOnEscape) {
      (event as KeyboardEvent).preventDefault();
      this.hide();
    }
  }

  onBackdropClick(event: MouseEvent): void {
    // Only close if clicking the backdrop itself, not the modal content
    if (event.target === event.currentTarget && this.closeOnBackdrop) {
      this.backdropClick.emit();
      this.hide();
    }
  }

  onCloseClick(): void {
    this.hide();
  }

  // ==================== FOCUS TRAP ====================

  private onModalOpen(): void {
    if (!this.visible) return;

    // Store previously focused element
    this.previouslyFocusedElement = document.activeElement as HTMLElement;

    // Lock body scroll
    if (this.lockScroll) {
      this.lockBodyScroll();
    }

    // Collect focusable elements
    if (this.focusTrap) {
      this.collectFocusableElements();
      // Focus first element or close button
      setTimeout(() => {
        if (this.closeButton?.nativeElement) {
          this.closeButton.nativeElement.focus();
        } else {
          this.focusFirstElement();
        }
      }, 100);
    }
  }

  private onModalClose(): void {
    // Restore focus
    if (this.previouslyFocusedElement) {
      this.previouslyFocusedElement.focus();
    }

    // Unlock body scroll
    this.unlockBodyScroll();
  }

  private collectFocusableElements(): void {
    if (!this.modalDialog?.nativeElement) return;

    const selector = [
      'button:not([disabled])',
      'a[href]',
      'input:not([disabled])',
      'select:not([disabled])',
      'textarea:not([disabled])',
      '[tabindex]:not([tabindex="-1"])',
    ].join(', ');

    this.focusableElements = Array.from(
      this.modalDialog.nativeElement.querySelectorAll(selector)
    ) as HTMLElement[];
  }

  @HostListener('keydown.tab', ['$event'])
  onTabKey(event: Event): void {
    if (!this.focusTrap || !this.visible || this.focusableElements.length === 0)
      return;

    const firstElement = this.focusableElements[0];
    const lastElement =
      this.focusableElements[this.focusableElements.length - 1];
    const activeElement = document.activeElement as HTMLElement;
    const keyboardEvent = event as KeyboardEvent;

    if (keyboardEvent.shiftKey) {
      // Shift + Tab - move backward
      if (
        activeElement === firstElement ||
        !this.focusableElements.includes(activeElement)
      ) {
        keyboardEvent.preventDefault();
        lastElement.focus();
      }
    } else {
      // Tab - move forward
      if (activeElement === lastElement) {
        keyboardEvent.preventDefault();
        firstElement.focus();
      }
    }
  }

  private focusFirstElement(): void {
    if (this.focusableElements.length > 0) {
      this.focusableElements[0].focus();
    }
  }

  // ==================== BODY SCROLL LOCK ====================

  private lockBodyScroll(): void {
    if (this.bodyScrollLock) return;

    const scrollY = window.scrollY;
    this.renderer.setStyle(document.body, 'position', 'fixed');
    this.renderer.setStyle(document.body, 'top', `-${scrollY}px`);
    this.renderer.setStyle(document.body, 'left', '0');
    this.renderer.setStyle(document.body, 'right', '0');
    this.renderer.setStyle(document.body, 'overflow', 'hidden');
    this.bodyScrollLock = true;
  }

  private unlockBodyScroll(): void {
    if (!this.bodyScrollLock) return;

    const scrollY = document.body.style.top;
    this.renderer.removeStyle(document.body, 'position');
    this.renderer.removeStyle(document.body, 'top');
    this.renderer.removeStyle(document.body, 'left');
    this.renderer.removeStyle(document.body, 'right');
    this.renderer.removeStyle(document.body, 'overflow');
    window.scrollTo(0, parseInt(scrollY || '0') * -1);
    this.bodyScrollLock = false;
  }

  // ==================== LEGACY CONVERSION ====================

  private _convertLegacyMode(mode: string): void {
    switch (mode) {
      case 'sidebar':
      case 'sidebar-right':
        this.position = 'sidebar-right';
        break;
      case 'sidebar-left':
        this.position = 'sidebar-left';
        break;
      case 'trough':
        this.position = 'bottom';
        break;
      case 'captive-modal':
        this.position = 'center';
        this.size = 'full';
        break;
      case 'standard-modal':
      default:
        this.position = 'center';
        break;
    }
  }
}

styleUrlsData.data:
@use '../../styles/mixins' as *;

// ============================================
// Personality-Driven Modal
// Uses application personality CSS variables
// ============================================

// Ensure host breaks out of any parent positioning context
:host {
  position: static;

  // Prevent any layout shifts on hover that could trigger re-renders
  &.animate-on-hover {
    animation: none !important;
  }
}

// Force GPU acceleration and prevent layout recalculations
.modal-overlay,
.modal-dialog {
  contain: layout style paint;
  transform: translateZ(0);
  will-change: transform, opacity;
}

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: none;
  z-index: var(--z-index-modal-backdrop, 1040);
  animation: personality-fade-in var(--animation-duration-fast, 100ms)
    var(--animation-easing, ease);

  @include reduced-motion {
    animation: none;
  }

  &:not(.with-backdrop) {
    background: transparent;
    pointer-events: none;
  }
}

@keyframes personality-fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.modal-dialog {
  position: fixed;
  display: flex;
  flex-direction: column;
  background: var(--background, #ffffff);
  color: var(--foreground, #212121);
  border-radius: var(--border-radius-sm, 4px);
  border: var(--border-width, 1px) solid var(--primary);
  box-shadow: var(--shadow-lg);
  max-height: 90vh;
  max-width: 90vw;
  overflow: hidden;
  z-index: var(--z-index-modal, 1050);
  animation: personality-modal-appear var(--animation-duration-fast, 100ms)
    var(--animation-easing, ease);

  @include reduced-motion {
    animation: none;
  }
}

@keyframes personality-modal-appear {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

// Position variants
:host(.position-center) {
  .modal-dialog {
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
  }
}

:host(.position-top) {
  .modal-dialog {
    top: 24px;
    left: 50%;
    transform: translateX(-50%);
    max-height: calc(100vh - 48px);
  }
}

:host(.position-sidebar-left) {
  .modal-dialog {
    top: 0;
    left: 0;
    height: 100vh;
    max-height: 100vh;
    border-radius: var(--border-radius-sm, 4px);
    animation: personality-slide-in-left var(--animation-duration-fast, 100ms)
      var(--animation-easing, ease);
  }
}

:host(.position-sidebar-right) {
  .modal-dialog {
    top: 0;
    right: 0;
    height: 100vh;
    max-height: 100vh;
    border-radius: var(--border-radius-sm, 4px);
    animation: personality-slide-in-right var(--animation-duration-fast, 100ms)
      var(--animation-easing, ease);
  }
}

:host(.position-bottom) {
  .modal-dialog {
    bottom: 0;
    left: 0;
    right: 0;
    max-height: 70vh;
    border-radius: var(--border-radius-sm, 4px);
    animation: personality-slide-up var(--animation-duration-fast, 100ms)
      var(--animation-easing, ease);
  }
}

@keyframes personality-slide-in-left {
  from {
    transform: translateX(-100%);
  }
  to {
    transform: translateX(0);
  }
}

@keyframes personality-slide-in-right {
  from {
    transform: translateX(100%);
  }
  to {
    transform: translateX(0);
  }
}

@keyframes personality-slide-up {
  from {
    transform: translateY(100%);
  }
  to {
    transform: translateY(0);
  }
}

// Size variants
:host(.size-sm) {
  .modal-dialog {
    width: 100%;
    max-width: 400px;
  }
}

:host(.size-md) {
  .modal-dialog {
    width: 100%;
    max-width: 600px;
  }
}

:host(.size-lg) {
  .modal-dialog {
    width: 100%;
    max-width: 900px;
  }
}

:host(.size-xl) {
  .modal-dialog {
    width: 100%;
    max-width: 1200px;
  }
}

:host(.size-full) {
  .modal-dialog {
    width: 100%;
    height: 100%;
    max-width: 100%;
    max-height: 100%;
    border-radius: var(--border-radius-sm, 4px);
  }
}

// Modal header
.modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  border-bottom: var(--border-width, 1px) solid var(--primary);
  flex-shrink: 0;
  background: var(--primary);
  color: var(--primary-foreground, #fff);
  position: relative;

  // Accent bar
  &::after {
    content: '';
    position: absolute;
    bottom: -8px;
    left: 0;
    right: 0;
    height: 4px;
    background: var(--secondary);
  }

  .modal-title {
    margin: 0;
    font-family: var(--font-heading, system-ui, sans-serif);
    font-size: 1.25rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    line-height: 1.3;
    color: var(--primary-foreground, #fff);
  }
}

.modal-close-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  border: 2px solid var(--primary-foreground, #fff);
  background: transparent;
  color: var(--primary-foreground, #fff);
  font-size: 1.25rem;
  font-weight: 700;
  line-height: 1;
  cursor: pointer;
  border-radius: var(--border-radius-sm, 4px);
  transition: background-color var(--animation-duration-fast, 100ms)
      var(--animation-easing, ease),
    transform var(--animation-duration-fast, 100ms)
      var(--animation-easing, ease);

  &:hover {
    background: var(--secondary);
    border-color: var(--secondary);
    color: #000;
    transform: scale(1.1);
  }

  &:focus {
    outline: 2px solid var(--secondary);
    outline-offset: 2px;
  }
}

.modal-body {
  flex: 1;
  padding: 24px;
  overflow-y: auto;
  overflow-x: hidden;
  font-family: var(--font-body, system-ui, sans-serif);
  font-size: 0.875rem;
  line-height: 1.6;
}

.modal-footer {
  display: flex;
  justify-content: flex-end;
  gap: 12px;
  padding: 16px 24px;
  border-top: 2px solid var(--primary);
  background: color-mix(in srgb, var(--primary) 5%, transparent);
  flex-shrink: 0;

  &:empty {
    display: none;
  }
}

// Visual variants
:host(.variant-glass) {
  .modal-dialog {
    background: rgba(255, 255, 255, 0.95);
    border-color: var(--primary);
  }

  .modal-header {
    background: linear-gradient(90deg, var(--primary), var(--secondary));
  }
}

:host(.variant-gradient) {
  .modal-dialog {
    background: repeating-linear-gradient(
      45deg,
      var(--background, #ffffff),
      var(--background, #ffffff) 10px,
      color-mix(in srgb, var(--primary) 5%, transparent) 10px,
      color-mix(in srgb, var(--primary) 5%, transparent) 20px
    );
    color: var(--foreground, #212121);

    .modal-header {
      background: var(--primary);
    }
  }
}

:host(.variant-bordered) {
  .modal-dialog {
    border-width: var(--border-width, 1px);
    box-shadow: var(--shadow-lg);
  }
}

// Legacy modal
.legacy-modal {
  position: fixed;
  background: var(--background, #ffffff);
  border: var(--border-width, 1px) solid var(--primary);
  border-radius: var(--border-radius-sm, 4px);
  box-shadow: var(--shadow-lg);
  z-index: 1000;
  color: var(--foreground, #212121);
  font-family: var(--font-body, system-ui, sans-serif);

  &.glass {
    background: rgba(255, 255, 255, 0.95);
    border-color: var(--primary);
    box-shadow: var(--shadow-lg);
  }

  &.gradient {
    background: repeating-linear-gradient(
      45deg,
      var(--primary),
      var(--primary) 10px,
      var(--secondary) 10px,
      var(--secondary) 20px
    );
    color: #fff;
    border: none;

    .modal-header {
      background: rgba(0, 0, 0, 0.2);
      border-bottom-color: rgba(255, 255, 255, 0.3);
    }
  }

  &.sm {
    font-size: 0.875rem;
    max-width: 320px;
    padding: 16px;
  }

  &.md {
    font-size: 1rem;
    padding: 24px;
  }

  &.lg {
    font-size: 1.125rem;
    padding: 32px;
  }

  &.standard-modal {
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 80%;
    max-width: 600px;
  }

  &.sidebar,
  &.sidebar-left {
    top: 0;
    left: 0;
    height: 100%;
    width: 320px;
    border-radius: var(--border-radius-sm, 4px);
    border-left: calc(var(--border-width, 1px) * 2) solid var(--primary);
  }

  &.sidebar-right {
    top: 0;
    right: 0;
    height: 100%;
    width: 320px;
    border-radius: var(--border-radius-sm, 4px);
    border-right: calc(var(--border-width, 1px) * 2) solid var(--primary);
  }

  &.trough {
    bottom: 0;
    left: 0;
    height: 200px;
    width: 100%;
    border-radius: var(--border-radius-sm, 4px);
    border-bottom: calc(var(--border-width, 1px) * 2) solid var(--primary);
  }

  &.captive-modal {
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    max-width: none;
    max-height: none;
    border: var(--border-width, 1px) solid var(--primary);
    border-radius: var(--border-radius-sm, 4px);
  }

  .modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 20px;
    border-bottom: var(--border-width, 1px) solid var(--primary);
    background: var(--primary);
    color: var(--primary-foreground, #fff);
    font-family: var(--font-heading, system-ui, sans-serif);
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;

    h2 {
      margin: 0;
      font-size: 1rem;
    }
  }

  .modal-content {
    padding: 20px;
    border-radius: var(--border-radius-sm, 4px);
  }
}

// Reduced motion
@include reduced-motion {
  .modal-overlay,
  .modal-dialog {
    animation: none;
  }
}

// ============================================
// Personality-Specific Modal Enhancements
// ============================================

// Architect personality - brutalist
body.personality-architect .modal-dialog {
  border-radius: 0;
  border: 3px solid var(--foreground);

  .modal-header {
    border-bottom-width: 3px;
    padding: 12px 16px;
  }
}

// Playful personality - bouncy animation
body.personality-playful .modal-dialog {
  animation: modal-bounce-in 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

@keyframes modal-bounce-in {
  0% {
    opacity: 0;
    transform: scale(0.8);
  }
  60% {
    transform: scale(1.05);
  }
  100% {
    opacity: 1;
    transform: scale(1);
  }
}

// Minimal personality - subtle fade
body.personality-minimal .modal-dialog {
  border: 1px solid var(--border);
  border-radius: 2px;
  box-shadow: 0 2px 20px rgba(0, 0, 0, 0.08);

  .modal-header {
    border-bottom: 1px solid var(--border);
    background: transparent;
    color: var(--foreground);
    text-transform: none;
    letter-spacing: normal;
  }
}

// Electric personality - glow overlay
body.personality-electric .modal-overlay {
  background: rgba(0, 0, 0, 0.6);
}

body.personality-electric .modal-dialog {
  box-shadow: 0 0 40px var(--primary-alpha-40, rgba(63, 81, 181, 0.4));

  .modal-header {
    background: var(--gradient-primary);
  }
}

// Soft Touch personality - rounded
body.personality-soft-touch .modal-dialog {
  border-radius: 20px;

  .modal-header {
    border-radius: 18px 18px 0 0;
  }
}

// Control Center - technical
body.personality-control-center .modal-dialog {
  border-radius: 4px;
  border: 1px solid var(--primary);

  .modal-header {
    background: var(--primary);
    border-bottom: 2px solid var(--foreground);
  }
}

// Gradient overlay variant
.modal-overlay-gradient {
  background: var(--gradient-modal-overlay, rgba(0, 0, 0, 0.7));
}

// Fullscreen modal variant
.modal-fullscreen {
  max-width: 100vw;
  max-height: 100vh;
  border-radius: 0;
  border: none;
}

