    background: var(--primary);
    color: var(--primary-foreground);
  }
}

// Enclosed variant
.tabs-enclosed {
  .tabs-header {
    border: 1px solid var(--border);
    border-radius: var(--border-radius-md, 4px);
    padding: 4px;
    gap: 0;
  }

  .tab-item {
    border-radius: var(--border-radius-sm, 2px);

    &.active {
      background: var(--primary);
      color: var(--primary-foreground);

      &::after {
        display: none;
      }
    }
  }
}

