@use '../../styles/mixins' as *;

.tile {
  padding: 0;
  margin: 0;
  @include pulse-animation(16s, (var(--accent), var(--complement)));
  .filter {
    margin: 5px;
    padding: 2rem 2rem;
    width: 100%;
    height: 100%;
    position: relative;
    background: var(--background-filter, rgba(255, 255, 255, 0.5));
    @include border-radius-standard(var(--border-radius, 4px));
    @include pulse-animation(16s, (var(--accent), var(--complement)));
    :hover {
      background: var(
        --hover-background-filter,
        var(--background-filter, rgba(255, 255, 255, 0.5))
      );
      @include transition-base(background, var(--transition-duration, 0.3s));
    }
  }
}
.default {
  @include border-base(4px, solid, var(--accent, #b1baec));
  @include border-radius-standard(8px);
  @include flex-column;
  justify-content: center;
  align-items: center;
  @include transition-base(box-shadow, 0.3s);
  background: var(--background-gradient, #5969c3);
  @include pulse-animation(16s, (var(--accent), var(--complement)));
  color: var(--foreground, #fff);
  @include box-shadow-multi-glow(
    var(--accent),
    var(--complement),
    20px,
    8px,
    20px,
    8px
  );
}

.tile.row {
  @include flex-row;
  align-items: center;
  justify-content: space-between;
  @include transition-base(box-shadow, 0.3s);
  background: var(--background, #5969c3);
  @include box-shadow-glow(var(--accent), 6px, 10px);
  box-shadow: 4px 4px 6px 10px var(--accent),
    inset 0 2px 12px 0 rgba(0, 0, 0, 0.15);
}

.tile:hover {
  @include box-shadow-inset(var(--accent), 1em, 0);
  box-shadow: inset 1px 2px 1em var(--accent), 2px 4px 8px 6px var(--complement);
}

.tile.light-mode {
  background-color: var(--accent, #b1baec);
  color: var(--foreground, #000);
}

.tile.dark-mode {
  background-color: var(--accent-shade-darken-50, #313a6c);
  color: var(--foreground, #fff);
}

.tile.fast-cycle-mode {
  background: var(--gradient-fastCycle);
  color: var(--foreground, #fff);
}

.tile-title {
  font-size: 1.2em;
  font-weight: bold;
  margin-bottom: 0.5em;
  color: var(--foreground, #fff);
}

.tile-content {
  font-size: 1em;
  color: var(--foreground, #fff);
}

.grid > .tile {
  width: 100%;
  height: 100%;
  aspect-ratio: 1 / 1;
}

:host {
  display: block;
  box-sizing: border-box;
  @include border-radius-standard(var(--border-radius, 1em));
  @include border-base(
    var(--border-width, 2px),
    solid,
    var(--border-color, transparent)
  );
  background: var(--background, #fff);
  color: var(--foreground, #222);
  @include transition-base(box-shadow, var(--transition-duration, 0.3s));
  position: relative;
  overflow: hidden;
}

.gradient-glow {
  border: solid var(--border-width, 4px) #0000;
  border-radius: calc(2 * var(--border-width, 4px));
  background: repeating-conic-gradient(
      from var(--angle, 0deg),
      var(--gradient-stops, #0000 0% 70%, #0000ff7f)
    )
    border-box;
  filter: var(--glow-filter, url(#glow-0));
  animation: glow-anim 2s linear infinite;
}

@keyframes glow-anim {
  to {
    --angle: 1turn;
  }
}

.electric-border {
  padding: 2px;
  border-radius: 24px;
  position: relative;
  background: linear-gradient(
      -30deg,
      var(--gradient-color, #ffbc00),
      transparent,
      var(--gradient-color, #ffbc00)
    ),
    linear-gradient(to bottom, var(--background, #222), var(--background, #222));
  border: 2px solid var(--electric-border-color, #dd8448);
  filter: url(#turbulent-displace);
}

.gradient-glow-card {
  --list: var(--gradient-colors, #ffbc00, #ff0058);
  --grad: linear-gradient(45deg, var(--list));
  border: solid 4px #0000;
  aspect-ratio: 7/10;
  border-radius: 1em;
  background: conic-gradient(rgb(0 0 0/ 0.75) 0 0) padding-box,
    var(--grad) border-box;
}

.gradient-glow-card::before {
  position: absolute;
  inset: 0;
  z-index: -1;
  background: var(--grad);
  filter: blur(0.75em);
  content: '';
}

.gradient-background {
  @include gradient-background('linear', '135deg', '#ffbc00', '#ff0058');
  @include animated-gradient(10s, 200%);
}

