(hex: string): string => {
  // Remove the leading '#' if present
  hex = hex.replace(/^#/, '');

  // Parse the hex string into its RGB components
  const bigint = parseInt(hex, 16);
  let r: number, g: number, b: number;

  if (hex.length === 6) {
    r = (bigint >> 16) & 255;
    g = (bigint >> 8) & 255;
    b = bigint & 255;
  } else if (hex.length === 3) {
    r = ((bigint >> 8) & 15) * 17;
    g = ((bigint >> 4) & 15) * 17;
    b = (bigint & 15) * 17;
  } else {
    throw new Error('Invalid hex color format');
  }

  return `${r}, ${g}, ${b}`;
}

